import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import './portal.css';
import { createClient } from '@supabase/supabase-js';
import { loadStripe } from '@stripe/stripe-js';
import { Elements, PaymentElement, useStripe, useElements } from '@stripe/react-stripe-js';
import * as XLSX from 'xlsx';
import { BarcodeDetector as BarcodeDetectorPolyfill } from 'barcode-detector';

// ─── Stripe Setup ───
const _stripePk = process.env.REACT_APP_STRIPE_PK || '';
let stripePromise = null;
try { if (_stripePk) stripePromise = loadStripe(_stripePk); }
catch(e) { console.warn('[Stripe] Init failed:', e.message); }

// ─── Brevo Email Setup ───
const _brevoKey = process.env.REACT_APP_BREVO_API_KEY || '';
const sendBrevoEmail=async({to,subject,htmlContent,textContent,senderName,senderEmail,attachment})=>{
  if(!_brevoKey){return{ok:false,error:'Brevo API key not configured (set REACT_APP_BREVO_API_KEY)'}}
  try{const payload={sender:{name:senderName||'National Sports Apparel',email:senderEmail||'noreply@nationalsportsapparel.com'},to:Array.isArray(to)?to:[{email:to}],subject,htmlContent:htmlContent||undefined,textContent:textContent||undefined};
    if(attachment&&attachment.length>0)payload.attachment=attachment;
    const r=await fetch('https://api.brevo.com/v3/smtp/email',{method:'POST',headers:{'accept':'application/json','content-type':'application/json','api-key':_brevoKey},
    body:JSON.stringify(payload)});
    const d=await r.json();if(!r.ok)return{ok:false,error:d.message||'Send failed'};return{ok:true,messageId:d.messageId}}
  catch(e){return{ok:false,error:e.message}}
};

// ─── Supabase Setup ───
const _sbUrl = process.env.REACT_APP_SUPABASE_URL || '';
const _sbKey = process.env.REACT_APP_SUPABASE_ANON_KEY || '';
let supabase = null;
try { if (_sbUrl && _sbKey && _sbUrl.startsWith('https://') && !_sbUrl.includes('your-project')) supabase = createClient(_sbUrl, _sbKey); }
catch(e) { console.warn('[Supabase] Init failed:', e.message); }

const _dbLoad = async () => {
  if (!supabase) return null;
  if (_dbSavingCount>0) { console.log('[DB] Skipping load — save in progress'); return null; }
  try {
    // Load all tables in parallel
    const [rTeam,rCust,rContacts,rVend,rProd,rProdInv,rEst,rEstArt,rEstItems,rEstDecos,
      rSO,rSOArt,rSOFirm,rSOItems,rSODecos,rSOPicks,rSOPOs,rSOJobs,
      rInv,rInvPay,rInvItems,rMsg,rMsgReads,rOMG,rOMGProd,rIssues,rAppState,
      rPromoProg,rPromoPeriods,rPromoUsage] = await Promise.all([
      supabase.from('team_members').select('*').order('name').limit(10000),
      supabase.from('customers').select('*').order('name').limit(10000),
      supabase.from('customer_contacts').select('*').limit(10000),
      supabase.from('vendors').select('*').order('name').limit(10000),
      supabase.from('products').select('*').order('name').limit(10000),
      supabase.from('product_inventory').select('*').limit(10000),
      supabase.from('estimates').select('*').order('id').limit(10000),
      supabase.from('estimate_art_files').select('*').limit(10000),
      supabase.from('estimate_items').select('*').order('item_index').limit(10000),
      supabase.from('estimate_item_decorations').select('*').order('deco_index').limit(10000),
      supabase.from('sales_orders').select('*').order('id').limit(10000),
      supabase.from('so_art_files').select('*').limit(10000),
      supabase.from('so_firm_dates').select('*').limit(10000),
      supabase.from('so_items').select('*').order('item_index').limit(10000),
      supabase.from('so_item_decorations').select('*').order('deco_index').limit(10000),
      supabase.from('so_item_pick_lines').select('*').limit(10000),
      supabase.from('so_item_po_lines').select('*').limit(10000),
      supabase.from('so_jobs').select('*').limit(10000),
      supabase.from('invoices').select('*').order('id').limit(10000),
      supabase.from('invoice_payments').select('*').limit(10000),
      supabase.from('invoice_items').select('*').limit(10000),
      supabase.from('messages').select('*').order('id').limit(10000),
      supabase.from('message_reads').select('*').limit(10000),
      supabase.from('omg_stores').select('*').order('id').limit(10000),
      supabase.from('omg_store_products').select('*').limit(10000),
      supabase.from('issues').select('*').limit(10000),
      supabase.from('app_state').select('*').limit(10000),
      supabase.from('customer_promo_programs').select('*').limit(10000),
      supabase.from('customer_promo_periods').select('*').limit(10000),
      supabase.from('customer_promo_usage').select('*').limit(10000),
    ]);
    // Check for critical errors on core tables only (child tables may not exist yet — 404 is OK)
    const coreResults=[{n:'team_members',r:rTeam},{n:'customers',r:rCust},{n:'vendors',r:rVend},{n:'products',r:rProd},{n:'estimates',r:rEst},{n:'sales_orders',r:rSO},{n:'invoices',r:rInv},{n:'messages',r:rMsg},{n:'omg_stores',r:rOMG}];
    const is404=r=>r.status===404||(r.error?.message||'').includes('does not exist')||(r.error?.code==='PGRST204');
    const errs=coreResults.filter(({r})=>r.error&&!is404(r));
    if(errs.length){console.error('[DB] Load errors:',errs.map(({n,r})=>`${n}: ${r.error.message}`));return null}
    // Helper: return data or empty array (safe for 404 / missing tables)
    const d=r=>r.data||[];
    const team=d(rTeam);const custRaw=d(rCust);const contacts=d(rContacts);
    const vendors=d(rVend);const prodRaw=d(rProd);const prodInv=d(rProdInv);
    const estRaw=d(rEst);const estArt=d(rEstArt);const estItems=d(rEstItems);const estDecos=d(rEstDecos);
    const soRaw=d(rSO);const soArt=d(rSOArt);const soFirm=d(rSOFirm);
    const soItems=d(rSOItems);const soDecos=d(rSODecos);const soPicks=d(rSOPicks);const soPOs=d(rSOPOs);const soJobs=d(rSOJobs);
    const invRaw=d(rInv);const invPay=d(rInvPay);const invItems=d(rInvItems);
    const msgRaw=d(rMsg);const msgReads=d(rMsgReads);
    const omgRaw=d(rOMG);const omgProd=d(rOMGProd);
    const issues=d(rIssues);
    // Promo data
    const promoPrograms=d(rPromoProg);const promoPeriods=d(rPromoPeriods);const promoUsage=d(rPromoUsage);
    // Parse app_state key-value pairs
    const appStateRaw=d(rAppState);
    const appState={};appStateRaw.forEach(r=>{try{appState[r.id]=JSON.parse(r.value)}catch{appState[r.id]=r.value}});
    // ─── Reconstruct nested objects ───
    // Product image backups from app_state (reliable fallback when image columns are missing)
    const _pimgMap={};appStateRaw.filter(r=>r.id.startsWith('_pimg_')).forEach(r=>{try{_pimgMap[r.id.slice(6)]=JSON.parse(r.value)}catch{}});
    // Customers: attach contacts array
    const customers=custRaw.map(c=>({...c,contacts:contacts.filter(ct=>ct.customer_id===c.id).sort((a,b)=>a.sort_order-b.sort_order).map(ct=>({name:ct.name,email:ct.email,phone:ct.phone,role:ct.role})),
      promo_programs:promoPrograms.filter(pp=>pp.customer_id===c.id),
      promo_periods:promoPeriods.filter(pp=>pp.customer_id===c.id),
      promo_usage:promoUsage.filter(pu=>promoPeriods.filter(pp=>pp.customer_id===c.id).some(pp=>pp.id===pu.period_id))}));
    // Products: attach _inv and _alerts from product_inventory
    const products=prodRaw.map(p=>{const invRows=prodInv.filter(pi=>pi.product_id===p.id);const _inv={};const _alerts={};invRows.forEach(r=>{_inv[r.size]=r.quantity;if(r.alert_threshold)_alerts[r.size]=r.alert_threshold});const _pimg=_pimgMap[p.id];return{...p,image_url:p.image_url||p.image_front_url||(_pimg&&_pimg.front)||'',back_image_url:p.back_image_url||p.image_back_url||(_pimg&&_pimg.back)||'',images:p.images||(_pimg&&_pimg.gallery)||[],_inv,_alerts}});
    // Estimates: attach items (with decorations) and art_files
    const estimates=estRaw.map(est=>{
      const art_files=estArt.filter(a=>a.estimate_id===est.id).map(a=>({id:a.id,name:a.name,deco_type:a.deco_type,ink_colors:a.ink_colors,thread_colors:a.thread_colors,art_size:a.art_size,art_sizes:a.art_sizes||{},garment_colors:a.garment_colors||{},files:a.files||[],mockup_files:a.mockup_files||[],item_mockups:a.item_mockups||{},prod_files:a.prod_files||[],notes:a.notes,status:a.status,uploaded:a.uploaded}));
      const items=estItems.filter(i=>i.estimate_id===est.id).sort((a,b)=>a.item_index-b.item_index).map(item=>{
        const decorations=estDecos.filter(d=>d.estimate_item_id===item.id).sort((a,b)=>a.deco_index-b.deco_index).map(d=>{const{id:_,estimate_item_id:__,deco_index:___,...rest}=d;return rest});
        const{id:_,estimate_id:__,item_index:___,...rest}=item;return{...rest,decorations}});
      return{...est,items,art_files}});
    // Sales Orders: attach items (with decorations, pick_lines, po_lines), art_files, firm_dates, jobs
    const sales_orders=soRaw.map(so=>{
      const art_files=soArt.filter(a=>a.so_id===so.id).map(a=>({id:a.id,name:a.name,deco_type:a.deco_type,ink_colors:a.ink_colors,thread_colors:a.thread_colors,art_size:a.art_size,art_sizes:a.art_sizes||{},garment_colors:a.garment_colors||{},files:a.files||[],mockup_files:a.mockup_files||[],item_mockups:a.item_mockups||{},prod_files:a.prod_files||[],notes:a.notes,status:a.status,uploaded:a.uploaded}));
      const firm_dates=soFirm.filter(f=>f.so_id===so.id).map(f=>({item_desc:f.item_desc,date:f.date,approved:f.approved}));
      const jobs=soJobs.filter(j=>j.so_id===so.id).map(j=>{const{so_id:_,...rest}=j;return rest});
      const items=soItems.filter(i=>i.so_id===so.id).sort((a,b)=>a.item_index-b.item_index).map(item=>{
        const decorations=soDecos.filter(d=>d.so_item_id===item.id).sort((a,b)=>a.deco_index-b.deco_index).map(d=>{const{id:_,so_item_id:__,deco_index:___,...rest}=d;return rest});
        const pick_lines=soPicks.filter(pk=>pk.so_item_id===item.id).map(pk=>{const{id:_,so_item_id:__,...rest}=pk;const sizes=rest.sizes||{};delete rest.sizes;return{...rest,...sizes}});
        const po_lines=soPOs.filter(po=>po.so_item_id===item.id).map(po=>{const{id:_,so_item_id:__,...rest}=po;const sizes=rest.sizes||{};delete rest.sizes;return{...rest,...sizes}});
        const{id:_,so_id:__,item_index:___,...rest}=item;return{...rest,decorations,pick_lines,po_lines}});
      return{...so,items,art_files,firm_dates,jobs}});
    // Invoices: attach payments and items
    const invoices=invRaw.map(inv=>{
      const payments=invPay.filter(p=>p.invoice_id===inv.id).map(p=>({amount:p.amount,method:p.method,ref:p.ref,date:p.date}));
      const items=invItems.filter(i=>i.invoice_id===inv.id).map(i=>({sku:i.sku,name:i.name,qty:i.qty,unit_price:i.unit_price,total:i.total,description:i.description}));
      return{...inv,payments,items:items.length?items:undefined}});
    // Messages: attach read_by array and parse tagged_members
    const messages=msgRaw.map(m=>{const tm=m.tagged_members;const mapped={...m,text:m.body||m.text,ts:m.created_at||m.ts};delete mapped.body;return{...mapped,read_by:msgReads.filter(r=>r.message_id===m.id).map(r=>r.user_id),tagged_members:Array.isArray(tm)?tm:(typeof tm==='string'?(() => {try{return JSON.parse(tm)}catch{return[]}})():[])}});
    // OMG Stores: attach products
    const omg_stores=omgRaw.map(s=>({...s,products:omgProd.filter(p=>p.store_id===s.id).map(p=>({sku:p.sku,name:p.name,color:p.color,retail:p.retail,cost:p.cost,deco_type:p.deco_type,deco_cost:p.deco_cost,sizes:p.sizes||{}}))}));
    const hasData=(customers.length>0)||(sales_orders.length>0);
    return{team,customers,vendors,products,estimates,sales_orders,invoices,messages,omg_stores,issues,appState,hasData};
  }catch(e){console.error('[DB] Load failed:',e);return null}
};
const _dbSeed = async (d) => {
  if (!supabase) return;
  // Seed core tables — team_members MUST succeed first (customers FK to team_members)
  const teamIds=new Set((d.team||[]).map(t=>t.id));
  if(d.team?.length){const{error:tErr}=await supabase.from('team_members').upsert(d.team.map(t=>({id:t.id,name:t.name,role:t.role,email:t.email,phone:t.phone,is_active:t.is_active!==false})),{onConflict:'id'});if(tErr)console.error('[DB] seed team_members:',tErr.message)}
  if(d.vendors?.length){const{error:vErr}=await supabase.from('vendors').upsert(d.vendors.map(v=>_pick(v,_vendCols)),{onConflict:'id'});if(vErr)console.error('[DB] seed vendors:',vErr.message)}
  // Customers + contacts — use _pick to strip unknown cols, null out invalid FKs
  const custIds=new Set((d.customers||[]).map(c=>c.id));
  if(d.customers?.length){
    const custRows=d.customers.map(c=>{const clean=_pick(c,_custCols);if(clean.primary_rep_id&&!teamIds.has(clean.primary_rep_id))clean.primary_rep_id=null;if(clean.parent_id&&!custIds.has(clean.parent_id))clean.parent_id=null;return clean});
    // Insert parent-less customers first, then those with parent_id (to satisfy FK)
    const noParent=custRows.filter(c=>!c.parent_id);const withParent=custRows.filter(c=>c.parent_id);
    if(noParent.length){const{error:cErr}=await supabase.from('customers').upsert(noParent,{onConflict:'id'});if(cErr)console.error('[DB] seed customers:',cErr.message)}
    if(withParent.length){const{error:cErr}=await supabase.from('customers').upsert(withParent,{onConflict:'id'});if(cErr)console.error('[DB] seed customers (parents):',cErr.message)}
    const allContacts=[];d.customers.forEach(c=>(c.contacts||[]).forEach((ct,i)=>allContacts.push({customer_id:c.id,name:ct.name,email:ct.email,phone:ct.phone,role:ct.role,sort_order:i})));
    if(allContacts.length){const{error:ctErr}=await supabase.from('customer_contacts').insert(allContacts);if(ctErr)console.error('[DB] seed contacts:',ctErr.message)}
  }
  // Products + inventory — strip extra fields
  if(d.products?.length){
    await supabase.from('products').upsert(d.products.map(p=>{const{_inv,_alerts,_colors,vendor_id,...rest}=p;return{...rest,vendor_id:vendor_id||null,_colors:_colors||null}}),{onConflict:'id'});
    const allInv=[];d.products.forEach(p=>{const inv=p._inv||{};const alerts=p._alerts||{};const allSizes=new Set([...Object.keys(inv),...Object.keys(alerts)]);allSizes.forEach(sz=>allInv.push({product_id:p.id,size:sz,quantity:inv[sz]||0,alert_threshold:alerts[sz]||null}))});
    if(allInv.length) await supabase.from('product_inventory').upsert(allInv,{onConflict:'product_id,size'});
  }
  // Seed estimates (decompose nested items/decorations)
  for(const est of(d.estimates||[])){await _dbSaveEstimate(est)}
  // Seed sales orders (decompose nested items/decorations/picks/pos/jobs)
  for(const so of(d.sales_orders||[])){await _dbSaveSO(so)}
  // Seed invoices (decompose payments)
  for(const inv of(d.invoices||[])){await _dbSaveInvoice(inv)}
  // Seed messages
  if(d.messages?.length){
    await supabase.from('messages').upsert(d.messages.map(m=>{const r=_pick(m,_msgCols);const core={};Object.keys(r).forEach(k=>{if(!_msgExtraCols.has(k))core[k]=r[k]});return core}),{onConflict:'id'});
    // Try saving extra columns (tagged_members, entity fields) — silently fail if columns don't exist
    const extras=d.messages.map(m=>{const r=_pick(m,_msgCols);const ex={id:m.id};_msgExtraCols.forEach(k=>{if(k in r&&r[k]!=null)ex[k]=r[k]});return ex}).filter(e=>Object.keys(e).length>1);
    if(extras.length)await supabase.from('messages').upsert(extras,{onConflict:'id'}).then(r=>{if(r.error)console.warn('[DB] message extras skipped:',r.error.message)});
    const reads=[];d.messages.forEach(m=>(m.read_by||[]).forEach(uid=>reads.push({message_id:m.id,user_id:uid})));
    if(reads.length) await supabase.from('message_reads').upsert(reads,{onConflict:'message_id,user_id'});
  }
  // Seed OMG stores
  if(d.omg_stores?.length){
    await supabase.from('omg_stores').upsert(d.omg_stores.map(s=>_pick(s,_omgStoreCols)),{onConflict:'id'});
    const allProds=[];d.omg_stores.forEach(s=>(s.products||[]).forEach(p=>allProds.push({store_id:s.id,sku:p.sku,name:p.name,color:p.color,retail:p.retail,cost:p.cost,deco_type:p.deco_type,deco_cost:p.deco_cost,sizes:p.sizes})));
    if(allProds.length) await supabase.from('omg_store_products').upsert(allProds,{onConflict:'store_id,sku'});
  }
};
// ─── Normalized Save Helpers ───
const _dbSaveEstimateInner = async (est) => {
  if(!supabase)return;
  return _dbSavingGuard(async()=>{let decoFailed=false;try{
    const{items,art_files,...estRow}=est;
    let{error:estErr}=await supabase.from('estimates').upsert(_pick(estRow,_estCols),{onConflict:'id'});
    if(estErr){
      const coreEstRow={};Object.keys(_pick(estRow,_estCols)).forEach(k=>{if(!_estExtraCols.has(k))coreEstRow[k]=_pick(estRow,_estCols)[k]});
      const retry=await supabase.from('estimates').upsert(coreEstRow,{onConflict:'id'});
      if(retry.error){console.error('[DB] estimates upsert failed:',retry.error.message);decoFailed=true}
      else console.warn('[DB] estimate saved with core columns only')
    }
    // Delete old children — must delete grandchildren (decorations) BEFORE estimate_items due to FK constraints
    const oldItemIds=(await supabase.from('estimate_items').select('id').eq('estimate_id',est.id)).data?.map(i=>i.id)||[];
    if(oldItemIds.length){
      await supabase.from('estimate_item_decorations').delete().in('estimate_item_id',oldItemIds);
    }
    await supabase.from('estimate_items').delete().eq('estimate_id',est.id);
    // Sync art_files: upsert current, delete removed (avoids DELETE+INSERT race condition)
    if(art_files?.length){
      let afRows=art_files.map(a=>({..._pick(a,_artCols),estimate_id:est.id}));
      const{error:afErr}=await supabase.from('estimate_art_files').upsert(afRows,{onConflict:'estimate_id,id'});
      if(afErr){
        if(afErr.message?.includes('art_sizes')||afErr.message?.includes('garment_colors')||afErr.message?.includes('item_mockups')||afErr.message?.includes('schema cache')){
          const coreRows=afRows.map(r=>{const cr={};Object.keys(r).forEach(k=>{if(!_artExtraCols.has(k))cr[k]=r[k]});return cr});
          const{error:afErr2}=await supabase.from('estimate_art_files').upsert(coreRows,{onConflict:'estimate_id,id'});
          if(afErr2)console.error('[DB] estimate_art_files upsert failed (core):',afErr2.message,afErr2.details);
        }else{console.error('[DB] estimate_art_files upsert failed:',afErr.message,afErr.details)}
      }
      const currentAfIds=art_files.map(a=>a.id).filter(Boolean);
      if(currentAfIds.length){
        const{data:existingAfs}=await supabase.from('estimate_art_files').select('id').eq('estimate_id',est.id);
        const toDeleteAf=(existingAfs||[]).filter(ea=>!currentAfIds.includes(ea.id)).map(ea=>ea.id);
        if(toDeleteAf.length)await supabase.from('estimate_art_files').delete().in('id',toDeleteAf);
      }
    }else{
      await supabase.from('estimate_art_files').delete().eq('estimate_id',est.id);
    }
    if(!items?.length){_dbSaveFailedIds.delete(est.id);_persistFailedIds();return true}
    for(let idx=0;idx<items.length;idx++){
      const{decorations,...itemData}=items[idx];
      let itemRow={..._pick(itemData,_itemCols),estimate_id:est.id,item_index:idx};
      let{data:inserted,error:itemErr}=await supabase.from('estimate_items').insert(itemRow).select('id').single();
      if(itemErr){
        // Retry with core columns only (strip columns from later migrations)
        const coreItemRow={};Object.keys(itemRow).forEach(k=>{if(!_itemExtraCols.has(k))coreItemRow[k]=itemRow[k]});
        const retry=await supabase.from('estimate_items').insert(coreItemRow).select('id').single();
        if(retry.error){console.error('[DB] estimate_items insert failed:',retry.error.message,retry.error.details);decoFailed=true;continue}
        else{inserted=retry.data;console.warn('[DB] estimate item saved with core columns only (missing DB columns?)')}
      }
      if(inserted&&decorations?.length){
        const decoRows=decorations.map((d,di)=>({..._pick(_sanitizeDeco(d),_decoCols),estimate_item_id:inserted.id,deco_index:di}));
        const{error:decoErr}=await supabase.from('estimate_item_decorations').insert(decoRows);
        if(decoErr){
          console.warn('[DB] estimate_item_decorations batch failed, retrying individually:',decoErr.message);
          for(const row of decoRows){
            const{error:rowErr}=await supabase.from('estimate_item_decorations').insert(row);
            if(rowErr){
              // Strip columns from later migrations that may not exist in production DB
              const coreRow={};Object.keys(row).forEach(k=>{if(!_decoExtraCols.has(k))coreRow[k]=row[k]});
              const{error:coreErr}=await supabase.from('estimate_item_decorations').insert(coreRow);
              if(coreErr){decoFailed=true;console.error('[DB] estimate deco row failed:',coreErr.message,JSON.stringify(row))}
              else console.warn('[DB] estimate deco saved with core columns only (missing DB columns?):',Object.keys(row).filter(k=>_decoExtraCols.has(k)&&row[k]!=null))
            }
          }
        }
      }
    }
    if(decoFailed){_dbSaveFailedIds.add(est.id);_persistFailedIds();if(_dbNotify)_dbNotify('Estimate save incomplete — some data may not have been saved to cloud','error');return false}
    _dbSaveFailedIds.delete(est.id);_persistFailedIds();return true;
  }catch(e){console.error('[DB] save estimate:',e);_dbSaveFailedIds.add(est.id);_persistFailedIds();if(_dbNotify)_dbNotify('Estimate save failed: '+e.message,'error');return false}});
};
const _dbSaveEstimate = (est) => _queuedEntitySave(est.id, est, _dbSaveEstimateInner);
const _dbSaveSOInner = async (so) => {
  if(!supabase)return;
  return _dbSavingGuard(async()=>{let saveFailed=false;try{
    const{items,art_files,firm_dates,jobs,...soRow}=so;
    let{error:soErr}=await supabase.from('sales_orders').upsert(_pick(soRow,_soCols),{onConflict:'id'});
    if(soErr){
      const coreSoRow={};Object.keys(_pick(soRow,_soCols)).forEach(k=>{if(!_soExtraCols.has(k))coreSoRow[k]=_pick(soRow,_soCols)[k]});
      const retry=await supabase.from('sales_orders').upsert(coreSoRow,{onConflict:'id'});
      if(retry.error){console.error('[DB] sales_orders upsert failed:',retry.error.message);saveFailed=true}
      else console.warn('[DB] SO saved with core columns only')
    }
    // Delete old children — must delete grandchildren (decorations/picks/POs) BEFORE so_items due to FK constraints
    const oldItemIds=(await supabase.from('so_items').select('id').eq('so_id',so.id)).data?.map(i=>i.id)||[];
    if(oldItemIds.length){
      await supabase.from('so_item_decorations').delete().in('so_item_id',oldItemIds);
      await supabase.from('so_item_pick_lines').delete().in('so_item_id',oldItemIds);
      await supabase.from('so_item_po_lines').delete().in('so_item_id',oldItemIds);
    }
    await supabase.from('so_items').delete().eq('so_id',so.id);
    // Sync jobs: upsert current jobs, delete removed ones (avoids DELETE+INSERT race condition)
    if(jobs?.length){
      const jobRows=jobs.map(j=>({..._pick(j,_jobCols),so_id:so.id}));
      const{error:jobErr}=await supabase.from('so_jobs').upsert(jobRows,{onConflict:'so_id,id'});
      if(jobErr){
        if(jobErr.message?.includes('schema cache')||jobErr.message?.includes('column')){
          const coreRows=jobRows.map(r=>{const cr={};Object.keys(r).forEach(k=>{if(!_jobExtraCols.has(k))cr[k]=r[k]});return cr});
          const{error:jobErr2}=await supabase.from('so_jobs').upsert(coreRows,{onConflict:'so_id,id'});
          if(jobErr2){console.error('[DB] so_jobs upsert failed (core):',jobErr2.message,jobErr2.details);saveFailed=true}
        }else{console.error('[DB] so_jobs upsert failed:',jobErr.message,jobErr.details);saveFailed=true}
      }
      // Delete jobs that no longer exist
      const currentJobIds=jobs.map(j=>j.id).filter(Boolean);
      if(currentJobIds.length){
        const{data:existingJobs}=await supabase.from('so_jobs').select('id').eq('so_id',so.id);
        const toDelete=(existingJobs||[]).filter(ej=>!currentJobIds.includes(ej.id)).map(ej=>ej.id);
        if(toDelete.length)await supabase.from('so_jobs').delete().in('id',toDelete);
      }
    }else{
      await supabase.from('so_jobs').delete().eq('so_id',so.id);
    }
    await supabase.from('so_firm_dates').delete().eq('so_id',so.id);
    // Sync art_files: upsert current, delete removed (avoids DELETE+INSERT race condition)
    if(art_files?.length){
      let soAfRows=art_files.map(a=>({..._pick(a,_artCols),so_id:so.id}));
      const{error:afErr}=await supabase.from('so_art_files').upsert(soAfRows,{onConflict:'so_id,id'});
      if(afErr){
        if(afErr.message?.includes('art_sizes')||afErr.message?.includes('garment_colors')||afErr.message?.includes('item_mockups')||afErr.message?.includes('schema cache')){
          const coreRows=soAfRows.map(r=>{const cr={};Object.keys(r).forEach(k=>{if(!_artExtraCols.has(k))cr[k]=r[k]});return cr});
          const{error:afErr2}=await supabase.from('so_art_files').upsert(coreRows,{onConflict:'so_id,id'});
          if(afErr2){console.error('[DB] so_art_files upsert failed (core):',afErr2.message,afErr2.details);saveFailed=true}
        }else{console.error('[DB] so_art_files upsert failed:',afErr.message,afErr.details);saveFailed=true}
      }
      // Delete art files that no longer exist
      const currentAfIds=art_files.map(a=>a.id).filter(Boolean);
      if(currentAfIds.length){
        const{data:existingAfs}=await supabase.from('so_art_files').select('id').eq('so_id',so.id);
        const toDeleteAf=(existingAfs||[]).filter(ea=>!currentAfIds.includes(ea.id)).map(ea=>ea.id);
        if(toDeleteAf.length)await supabase.from('so_art_files').delete().in('id',toDeleteAf);
      }
    }else{
      await supabase.from('so_art_files').delete().eq('so_id',so.id);
    }
    if(firm_dates?.length){const{error:fdErr}=await supabase.from('so_firm_dates').insert(firm_dates.map(f=>({..._pick(f,_firmDateCols),so_id:so.id})));if(fdErr){console.error('[DB] so_firm_dates insert failed:',fdErr.message);saveFailed=true}}
    if(!items?.length){if(saveFailed){_dbSaveFailedIds.add(so.id);_persistFailedIds();if(_dbNotify)_dbNotify('Sales order save incomplete — some data may not have been saved to cloud','error');return false}_dbSaveFailedIds.delete(so.id);_persistFailedIds();return true}
    for(let idx=0;idx<items.length;idx++){
      const{decorations,pick_lines,po_lines,...itemData}=items[idx];
      // Separate size fields from pick_lines/po_lines back into sizes JSONB
      let soItemRow={..._pick(itemData,_itemCols),so_id:so.id,item_index:idx};
      let{data:inserted,error:itemErr}=await supabase.from('so_items').insert(soItemRow).select('id').single();
      if(itemErr){
        const coreItemRow={};Object.keys(soItemRow).forEach(k=>{if(!_itemExtraCols.has(k))coreItemRow[k]=soItemRow[k]});
        const retry=await supabase.from('so_items').insert(coreItemRow).select('id').single();
        if(retry.error){console.error('[DB] so_items insert failed:',retry.error.message,retry.error.details);saveFailed=true;continue}
        else{inserted=retry.data;console.warn('[DB] so item saved with core columns only')}
      }
      if(!inserted)continue;
      if(decorations?.length){
        const decoRows=decorations.map((d,di)=>({..._pick(_sanitizeDeco(d),_decoCols),so_item_id:inserted.id,deco_index:di}));
        const{error:decoErr}=await supabase.from('so_item_decorations').insert(decoRows);
        if(decoErr){
          console.warn('[DB] so_item_decorations batch failed, retrying individually:',decoErr.message);
          for(const row of decoRows){
            const{error:rowErr}=await supabase.from('so_item_decorations').insert(row);
            if(rowErr){
              // Strip columns from later migrations that may not exist in production DB
              const coreRow={};Object.keys(row).forEach(k=>{if(!_decoExtraCols.has(k))coreRow[k]=row[k]});
              const{error:coreErr}=await supabase.from('so_item_decorations').insert(coreRow);
              if(coreErr){saveFailed=true;console.error('[DB] so deco row failed:',coreErr.message,JSON.stringify(row))}
              else console.warn('[DB] so deco saved with core columns only (missing DB columns?):',Object.keys(row).filter(k=>_decoExtraCols.has(k)&&row[k]!=null))
            }
          }
        }
      }
      if(pick_lines?.length){
        const pickRows=pick_lines.map(pk=>{const{pick_id,status,created_at,memo,ship_dest,ship_addr,deco_vendor,...sizes}=pk;
          return{so_item_id:inserted.id,pick_id,status,created_at,memo,ship_dest,ship_addr,deco_vendor,sizes}});
        const{error:pickErr}=await supabase.from('so_item_pick_lines').insert(pickRows);
        if(pickErr)console.error('[DB] so_item_pick_lines insert failed:',pickErr.message,pickErr.details);
      }
      if(po_lines?.length){
        const poRows=po_lines.map(po=>{const{po_id,vendor,received,cancelled,shipments,status,created_at,expected_date,memo,po_type,deco_vendor,deco_type,unit_cost,drop_ship,...sizes}=po;
          return{so_item_id:inserted.id,po_id,vendor,received:received||{},cancelled:cancelled||{},shipments:shipments||[],status,created_at,expected_date,memo,sizes:{...sizes,po_type:po_type||undefined,deco_vendor:deco_vendor||undefined,deco_type:deco_type||undefined,unit_cost:unit_cost||undefined,drop_ship:drop_ship||undefined}}});
        const{error:poErr}=await supabase.from('so_item_po_lines').insert(poRows);
        if(poErr)console.error('[DB] so_item_po_lines insert failed:',poErr.message,poErr.details);
      }
    }
    if(saveFailed){_dbSaveFailedIds.add(so.id);_persistFailedIds();if(_dbNotify)_dbNotify('Sales order save incomplete — some data may not have been saved to cloud','error');return false}
    _dbSaveFailedIds.delete(so.id);_persistFailedIds();return true;
  }catch(e){console.error('[DB] save SO:',e);_dbSaveFailedIds.add(so.id);_persistFailedIds();if(_dbNotify)_dbNotify('Sales order save failed: '+e.message,'error');return false}});
};
const _dbSaveSO = (so) => _queuedEntitySave(so.id, so, _dbSaveSOInner);
const _invCols=['id','customer_id','so_id','date','due_date','total','paid','memo','status','type','inv_type','deposit_pct','tax','tax_rate','tax_exempt','shipping','cc_fee','email_status','email_sent_at','line_items','qb_invoice_id','tc_reported','tc_tax','created_at','updated_at'];
const _dbSaveInvoice = async (inv) => {
  if(!supabase)return;
  return _dbSavingGuard(async()=>{try{
    const{payments,items,...rest}=inv;
    const{error:invErr}=await supabase.from('invoices').upsert(_pick(rest,_invCols),{onConflict:'id'});
    if(invErr){console.error('[DB] invoices upsert failed:',invErr.message);_dbSaveFailedIds.add(inv.id);_persistFailedIds();return false}
    // Upsert payments instead of DELETE+INSERT to avoid race condition
    if(payments?.length){
      await supabase.from('invoice_payments').delete().eq('invoice_id',inv.id);
      await supabase.from('invoice_payments').insert(payments.map(p=>({amount:p.amount,method:p.method,ref:p.ref,date:p.date,cc_fee:p.cc_fee,invoice_id:inv.id})));
    }
    if(items?.length){
      await supabase.from('invoice_items').delete().eq('invoice_id',inv.id);
      await supabase.from('invoice_items').insert(items.map(i=>({sku:i.sku,name:i.name,qty:i.qty,unit_price:i.unit_price,total:i.total,description:i.description,invoice_id:inv.id})));
    }
    _dbSaveFailedIds.delete(inv.id);_persistFailedIds();return true;
  }catch(e){console.error('[DB] save invoice:',e);_dbSaveFailedIds.add(inv.id);_persistFailedIds();return false}});
};
let _dbNotify=null; // set by App component for visible error toasts
const _dbSaveCustomer = async (c) => {
  if(!supabase){console.warn('[DB] save customer skipped — no supabase');return false}
  try{
    const{contacts,_oe,_os,_oi,_ob,...custRow}=c;
    custRow.updated_at=new Date().toISOString();
    if(!custRow.created_at)custRow.created_at=custRow.updated_at;
    const{error:custErr}=await supabase.from('customers').upsert(_pick(custRow,_custCols),{onConflict:'id'});
    if(custErr){console.error('[DB] save customer upsert error:',custErr.message);_dbSaveFailedIds.add(c.id);_persistFailedIds();if(_dbNotify)_dbNotify('Customer save failed: '+custErr.message,'error');return false}
    // Upsert contacts then delete removed ones (avoids DELETE+INSERT race condition)
    if(contacts?.length){
      const contactRows=contacts.map((ct,i)=>({customer_id:c.id,name:ct.name,email:ct.email,phone:ct.phone,role:ct.role,sort_order:i}));
      const{error:ctErr}=await supabase.from('customer_contacts').upsert(contactRows,{onConflict:'customer_id,sort_order'});
      if(ctErr){console.error('[DB] upsert contacts error:',ctErr.message);
        // Fallback: DELETE+INSERT if upsert constraint doesn't exist
        await supabase.from('customer_contacts').delete().eq('customer_id',c.id);
        await supabase.from('customer_contacts').insert(contactRows);
      }else{
        // Delete contacts beyond current count
        const{data:existingCts}=await supabase.from('customer_contacts').select('sort_order').eq('customer_id',c.id);
        const toDelete=(existingCts||[]).filter(ec=>ec.sort_order>=contacts.length);
        if(toDelete.length)await supabase.from('customer_contacts').delete().eq('customer_id',c.id).gte('sort_order',contacts.length);
      }
    }else{
      await supabase.from('customer_contacts').delete().eq('customer_id',c.id);
    }
    _dbSaveFailedIds.delete(c.id);_persistFailedIds();console.log('[DB] Customer saved:',c.id,c.name);return true;
  }catch(e){console.error('[DB] save customer:',e);_dbSaveFailedIds.add(c.id);_persistFailedIds();if(_dbNotify)_dbNotify('Customer save failed: '+e.message,'error');return false}
};
