// ─── Cloudinary Config ───
const CLOUDINARY_CLOUD='dwlyljyuz';
const CLOUDINARY_PRESET='ml_default_nsaportal';
const cloudUpload=async(file,folder='nsa-products')=>{const fd=new FormData();fd.append('file',file);fd.append('upload_preset',CLOUDINARY_PRESET);fd.append('folder',folder);const resType=file.type?.startsWith('image/')?'image':'auto';const r=await fetch(`https://api.cloudinary.com/v1_1/${CLOUDINARY_CLOUD}/${resType}/upload`,{method:'POST',body:fd});const d=await r.json();if(d.error)throw new Error(d.error.message);return d.secure_url};
const fileUpload=async(file,folder='nsa-art-files')=>{const fd=new FormData();fd.append('file',file);fd.append('upload_preset',CLOUDINARY_PRESET);fd.append('folder',folder);fd.append('filename_override',file.name);const r=await fetch(`https://api.cloudinary.com/v1_1/${CLOUDINARY_CLOUD}/auto/upload`,{method:'POST',body:fd});const d=await r.json();if(d.error)throw new Error(d.error.message);return d.secure_url};
const isUrl=s=>typeof s==='string'&&(s.startsWith('http://')||s.startsWith('https://'));
const fileDisplayName=f=>{if(typeof f==='object'&&f?.name)return f.name;const s=typeof f==='string'?f:(f?.url||'');return isUrl(s)?decodeURIComponent(s.split('/').pop().split('?')[0]):s};
const _isDownloadOnly=u=>{const e=_urlExt(u);return['ai','eps','dst','psd','tiff','tif','cdr'].includes(e)};
const openFile=f=>{const u=typeof f==='string'?f:(f?.url||'');if(isUrl(u)){if(_isPdfUrl(u)){window.open('https://docs.google.com/gview?url='+encodeURIComponent(u)+'&embedded=true','_blank')}else if(_isDownloadOnly(u)){const a=document.createElement('a');a.href=u;a.download=typeof f==='object'&&f?.name?f.name:decodeURIComponent(u.split('/').pop().split('?')[0]);a.target='_blank';a.rel='noopener';document.body.appendChild(a);a.click();document.body.removeChild(a)}else{window.open(u,'_blank')}}else if(u){nf('Legacy file: '+u+' — re-upload to enable downloads')}};
const _urlExt=u=>{if(!u||typeof u!=='string')return '';const clean=u.split('?')[0].split('#')[0];const m=clean.match(/\.(\w+)$/);return m?m[1].toLowerCase():''};
const _isImgUrl=u=>{const e=_urlExt(u);return['png','jpg','jpeg','gif','webp','svg','bmp'].includes(e)};
const _isPdfUrl=u=>_urlExt(u)==='pdf';
const _cloudinaryPdfThumb=u=>{if(!u||!u.includes('cloudinary.com'))return null;
  // Replace raw/upload with image/upload so transformations work, then add pg_1 transform
  let t=u.replace('/raw/upload/','/image/upload/').replace('/video/upload/','/image/upload/');
  return t.replace('/image/upload/','/image/upload/w_600,pg_1,f_jpg/')};
const ImgUpload=({url,onUpload,size=48,onError})=>{const[drag,setDrag]=React.useState(false);const[uploading,setUploading]=React.useState(false);const[err,setErr]=React.useState(false);
  const doUpload=async(file)=>{if(!file||!file.type.startsWith('image/')){if(onError)onError('Please select an image file');return}setUploading(true);setErr(false);try{const u=await cloudUpload(file);onUpload(u)}catch(e){console.error('Upload failed',e);setErr(true);if(onError)onError('Upload failed: '+e.message)}finally{setUploading(false)}};
  return<div style={{width:size,height:size,borderRadius:6,border:err?'2px solid #dc2626':drag?'2px solid #3b82f6':'1px solid #e2e8f0',background:drag?'#eff6ff':err?'#fef2f2':'#f8fafc',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,cursor:'pointer',overflow:'hidden',position:'relative'}}
    onDragOver={e=>{e.preventDefault();setDrag(true)}} onDragLeave={()=>setDrag(false)}
    onDrop={e=>{e.preventDefault();setDrag(false);doUpload(e.dataTransfer.files[0])}}
    onClick={()=>{const inp=document.createElement('input');inp.type='file';inp.accept='image/*';inp.onchange=()=>doUpload(inp.files[0]);inp.click()}}>
    {uploading?<span style={{fontSize:10,color:'#3b82f6',fontWeight:600}}>...</span>
    :url?<img src={url} alt="" style={{width:'100%',height:'100%',objectFit:'cover'}} onError={e=>{e.target.style.display='none'}}/>
    :err?<span style={{fontSize:size>40?14:10,color:'#dc2626'}}>!</span>
    :<span style={{fontSize:size>40?18:12,opacity:0.3}}>📷</span>}
  </div>};
// Multi-image gallery with drag-and-drop (for product images)
const ImgGallery=({images=[],onUpdate,onError,maxImages=10})=>{
  const[uploading,setUploading]=React.useState(false);const[drag,setDrag]=React.useState(false);
  const doUpload=async(files)=>{
    const imgFiles=Array.from(files).filter(f=>f.type.startsWith('image/'));
    if(imgFiles.length===0){if(onError)onError('Please select image files');return}
    if((images||[]).length+imgFiles.length>maxImages){if(onError)onError('Max '+maxImages+' images');return}
    setUploading(true);
    const newUrls=[];
    for(const f of imgFiles){
      try{const u=await cloudUpload(f);newUrls.push(u)}catch(e){if(onError)onError('Upload failed: '+e.message)}
    }
    if(newUrls.length>0)onUpdate([...(images||[]),...newUrls]);
    setUploading(false);
  };
  const removeImg=(idx)=>onUpdate((images||[]).filter((_,i)=>i!==idx));
  const moveImg=(from,to)=>{const arr=[...(images||[])];const[item]=arr.splice(from,1);arr.splice(to,0,item);onUpdate(arr)};
  return<div>
    <div style={{display:'flex',gap:6,flexWrap:'wrap',marginBottom:6}}>
      {(images||[]).map((url,i)=><div key={i} style={{width:72,height:72,borderRadius:6,border:'1px solid #e2e8f0',overflow:'hidden',position:'relative',background:'#f8fafc'}}>
        <img src={url} alt="" style={{width:'100%',height:'100%',objectFit:'cover'}} onError={e=>{e.target.style.display='none'}}/>
        <div style={{position:'absolute',top:0,right:0,display:'flex',gap:1}}>
          {i>0&&<button style={{background:'rgba(0,0,0,0.5)',color:'white',border:'none',cursor:'pointer',fontSize:9,padding:'1px 3px',borderRadius:2}} onClick={()=>moveImg(i,i-1)}>◀</button>}
          <button style={{background:'rgba(220,38,38,0.8)',color:'white',border:'none',cursor:'pointer',fontSize:10,padding:'1px 4px',borderRadius:2}} onClick={()=>removeImg(i)}>×</button>
        </div>
        <div style={{position:'absolute',bottom:0,left:0,background:'rgba(0,0,0,0.5)',color:'white',fontSize:8,padding:'1px 4px'}}>{i===0?'Primary':i+1}</div>
      </div>)}
    </div>
    {/* Drop zone for adding images */}
    <div style={{border:drag?'2px dashed #3b82f6':'2px dashed #d1d5db',borderRadius:8,padding:uploading?'8px':'12px 16px',textAlign:'center',
      background:drag?'#eff6ff':'#fafafa',cursor:'pointer',transition:'all 0.15s'}}
      onDragOver={e=>{e.preventDefault();setDrag(true)}} onDragLeave={()=>setDrag(false)}
      onDrop={e=>{e.preventDefault();setDrag(false);doUpload(e.dataTransfer.files)}}
      onClick={()=>{const inp=document.createElement('input');inp.type='file';inp.accept='image/*';inp.multiple=true;inp.onchange=()=>doUpload(inp.files);inp.click()}}>
      {uploading?<span style={{fontSize:11,color:'#3b82f6',fontWeight:600}}>Uploading...</span>
      :<><div style={{fontSize:11,color:drag?'#2563eb':'#64748b',fontWeight:600}}>{drag?'Drop images here':'Click or drag & drop images'}</div>
        <div style={{fontSize:9,color:'#94a3b8',marginTop:2}}>{(images||[]).length}/{maxImages} images · JPG, PNG, WebP</div></>}
    </div>
  </div>};
// ── PDF.js Setup (for NetSuite PDF import) ──
const PDFJS_CDN='https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174';
let _pdfjsLoaded=false;
const loadPdfJs=()=>{
  if(_pdfjsLoaded)return Promise.resolve();
  return new Promise((resolve,reject)=>{
    if(window.pdfjsLib){_pdfjsLoaded=true;resolve();return}
    const script=document.createElement('script');
    script.src=PDFJS_CDN+'/pdf.min.js';
    script.onload=()=>{window.pdfjsLib.GlobalWorkerOptions.workerSrc=PDFJS_CDN+'/pdf.worker.min.js';_pdfjsLoaded=true;resolve()};
    script.onerror=()=>reject(new Error('Failed to load PDF.js'));
    document.head.appendChild(script);
  });
};
const extractPdfText=async(file)=>{
  await loadPdfJs();
  const ab=await file.arrayBuffer();
  const pdf=await window.pdfjsLib.getDocument({data:ab}).promise;
  let fullText='';
  const pages=[];// per-page text for multi-document splitting
  for(let i=1;i<=pdf.numPages;i++){
    const page=await pdf.getPage(i);
    const content=await page.getTextContent();
    // Group text items into rows using Y position, then sort by X within each row
    const items=content.items.filter(it=>it.str.trim());
    if(items.length===0){pages.push('');continue}
    // Build rows by grouping items with similar Y coordinates (within 5 units)
    const rows=[];
    items.forEach(it=>{
      const y=Math.round(it.transform[5]);const x=it.transform[4];
      const w=it.width||it.str.length*5;
      let row=rows.find(r=>Math.abs(r.y-y)<=5);
      if(!row){row={y,items:[]};rows.push(row)}
      row.items.push({x,w,str:it.str});
    });
    // Sort rows top-to-bottom (higher Y = higher on page in PDF coords)
    rows.sort((a,b)=>b.y-a.y);
    let pageText='';
    rows.forEach(row=>{
      row.items.sort((a,b)=>a.x-b.x);
      // Join items — insert tab when horizontal gap suggests a new column
      let line='';
      row.items.forEach((it,idx)=>{
        if(idx>0){
          const prev=row.items[idx-1];
          const gap=it.x-(prev.x+prev.w);
          line+=gap>15?'\t':gap>1?' ':'';
        }
        line+=it.str;
      });
      pageText+=line+'\n';
    });
    pages.push(pageText);
    fullText+=pageText+'\n';
  }
  return{fullText,pages};
};
const parseNetSuitePdf=(text,docType,products)=>{
  const result={docNumber:'',date:'',customerName:'',terms:'',memo:'',subtotal:0,tax:0,shipping:0,total:0,lineItems:[],rawText:text,confidence:'low',warnings:[]};
  const _products=products||[];
  const lines=text.split('\n').map(l=>l.trim()).filter(Boolean);
  const SZ_RE=/[-\s](XXS|XS|YXS|YS|YM|YL|YXL|S|M|L|XL|2XL|3XL|4XL|5XL|OSFA)$/i;

  // ── Extract document number ──
  const docPatterns=[
    /(?:Estimate|EST)[#\s:]*#?(EST-?\d+)/i,
    /(?:Sales Order|SO)[#\s:]*#?(SO-?\d+)/i,
    /(?:Purchase Order|PO)[#\s:]*#?(PO-?\d+)/i,
    /(?:Invoice|INV)[#\s:]*#?(INV-?\d+)/i,
    /#(EST\d+)/i,/#(SO-?\d+)/i,/#(PO-?\d+)/i,/#(INV-?\d+)/i,
    /(?:Estimate|Sales Order|Invoice|Purchase Order)\s*(?:#|No\.?|Number)\s*:?\s*(\d+)/i,
    /(?:Estimate|Sales Order|Invoice|Purchase Order)\s*#?\s*(\d{3,})/i,
    /(?:Document|Transaction|Order)\s*(?:#|No\.?|Number)\s*:?\s*(\d+)/i
  ];
  // For tab-separated text, also try extracting from lines like "Estimate #\t1234"
  for(const pat of docPatterns){const m=text.match(pat);if(m){result.docNumber=m[1];break}}
  if(!result.docNumber){
    for(const line of lines){
      const tabMatch=line.match(/^(?:Estimate|Sales Order|Invoice|Purchase Order)\s*(?:#|No\.?|Number)\s*:?\t+(\d+)/i)
        ||line.match(/^(?:Estimate|Sales Order|Invoice|Purchase Order)\s*#\s*\t+(\S+)/i);
      if(tabMatch){result.docNumber=tabMatch[1];break}
    }
  }

  // ── Extract date ──
  const dateMatch=text.match(/(?:Date|Ordered|Created|Invoice Date|Transaction Date)[:\s]*(\d{1,2}\/\d{1,2}\/\d{2,4})/i)
    ||text.match(/(\d{1,2}\/\d{1,2}\/\d{4})/);
  if(dateMatch)result.date=dateMatch[1];

  // ── Extract terms ──
  const termsMatch=text.match(/(?:Terms|Payment Terms)[:\s]*([^\n\t]+)/i);
  if(termsMatch)result.terms=termsMatch[1].trim();

  // ── Extract memo ──
  for(const line of lines){
    const memoMatch=line.match(/^Memo[:\s]*\t+(.*)/i)||line.match(/^Memo[:\s]+(.+)/i);
    if(memoMatch){const mv=memoMatch[1].trim();if(mv&&!/^(Terms|Date|Item|Quantity)/i.test(mv)){result.memo=mv;break}}
  }

  // ── Extract customer/Bill To ──
  let custFound=false;
  for(let i=0;i<lines.length&&!custFound;i++){
    if(/^(Bill\s*To|Sold\s*To|Customer|Ship\s*To)\b/i.test(lines[i])){
      const nameLines=[];
      for(let j=i+1;j<Math.min(i+5,lines.length);j++){
        const l=lines[j];
        if(/^(Ship\s*To|Date|Terms|Item|Quantity|Due|PO\s*#|Rep|Memo)/i.test(l))break;
        if(/^\d{1,2}\/\d{1,2}\/\d{2,4}/.test(l))break;
        if(l.length<2)break;
        nameLines.push(l);
      }
      if(nameLines.length>0){
        result.customerName=nameLines[0].replace(/\t.*/,'').trim();
        custFound=true;
      }
    }
  }

  // ── Extract totals ──
  // Look for totals that appear after the items section (tab-separated label + value)
  const pN=s=>{const m=s.match(/\$?\s*([\d,]+\.?\d*)/);return m?parseFloat(m[1].replace(/,/g,'')):0};
  const pNfromLine=line=>{
    // Extract the last dollar amount from a line (handles tab-separated totals)
    const parts=line.split('\t');
    for(let k=parts.length-1;k>=0;k--){
      const v=parts[k].trim().replace(/[$,]/g,'');
      if(/^\d+\.?\d*$/.test(v)&&parseFloat(v)>0)return parseFloat(v);
    }
    return pN(line);
  };
  for(const line of lines){
    const lt=line.replace(/\t.*/,'').trim();// first cell only for label matching
    if(/^Subtotal$/i.test(lt))result.subtotal=pNfromLine(line);
    else if(/^Tax\b/i.test(lt))result.tax=pNfromLine(line);
    else if(/^Shipping$/i.test(lt))result.shipping=pNfromLine(line);
    else if(/^Total$/i.test(lt))result.total=pNfromLine(line);
  }

  // ── Parse line items ──
  // NSA NetSuite PDFs: 2-line format per item
  // Line 1: Quantity \t Item (SKU : SKU-SIZE) \t [Options] \t Tax(Yes/No) \t Rate \t Amount
  // Line 2: Description (product name - Color - Size)
  // Detect header row
  let headerIdx=-1;
  for(let i=0;i<lines.length;i++){
    const l=lines[i].toLowerCase();
    if((l.includes('quantity')||l.includes('qty'))&&(l.includes('item')||l.includes('sku'))&&(l.includes('amount')||l.includes('rate'))){
      headerIdx=i;break;
    }
  }

  const isEndMarker=l=>/^(Subtotal|Total$|Tax\b|Discount|Thank you|Comments|Notes$|Memo$|Terms$)/i.test(l.replace(/\t.*/,'').trim());
  // Detect page breaks and repeated headers from multi-page PDFs (skip, don't end)
  const isPageBreak=l=>{const t=l.replace(/\t.*/,'').trim();return/^Page\s+\d/i.test(t)};
  const isRepeatedHeader=l=>{const lo=l.toLowerCase();return(lo.includes('quantity')||lo.includes('qty'))&&(lo.includes('item')||lo.includes('sku'))&&(lo.includes('amount')||lo.includes('rate'))};
  // Check if a line starts with a quantity number (item data line vs description line)
  const isItemLine=line=>{
    const p=line.split('\t')[0]?.trim();
    return/^\d+$/.test(p);
  };

  // Collect 2-line item pairs from after the header
  const itemPairs=[];// [{dataLine, descLine}]
  if(headerIdx>=0){
    let i=headerIdx+1;
    while(i<lines.length){
      const line=lines[i];
      if(isEndMarker(line))break;
      if(!line.trim()||isPageBreak(line)||isRepeatedHeader(line)){i++;continue}

      if(isItemLine(line)){
        // This is a data line (qty/sku/rate/amount) — next non-empty line is description
        let descLine='';
        let nextIdx=i+1;
        // Skip page breaks/headers between data line and description
        while(nextIdx<lines.length&&(isPageBreak(lines[nextIdx])||isRepeatedHeader(lines[nextIdx])||!lines[nextIdx].trim()))nextIdx++;
        if(nextIdx<lines.length&&!isItemLine(lines[nextIdx])&&!isEndMarker(lines[nextIdx])){
          descLine=lines[nextIdx];
          i=nextIdx+1;
        } else {i++}
        itemPairs.push({dataLine:line,descLine});
      } else {
        // Standalone description line (might be continuation or orphan)
        if(itemPairs.length>0&&!itemPairs[itemPairs.length-1].descLine){
          itemPairs[itemPairs.length-1].descLine=line;
        }
        i++;
      }
    }
  } else {
    // No header — try scanning for qty-starting lines
    result.warnings.push('Could not detect item table header — trying pattern-based parsing');
    for(let i=0;i<lines.length;i++){
      if(isEndMarker(lines[i])||isPageBreak(lines[i])||isRepeatedHeader(lines[i]))continue;
      if(isItemLine(lines[i])){
        let descLine='';
        if(i+1<lines.length&&!isItemLine(lines[i+1])&&!isEndMarker(lines[i+1])){
          descLine=lines[i+1];i++;
        }
        itemPairs.push({dataLine:lines[i]||lines[i-1],descLine});
      }
    }
  }

  // Parse each item pair
  const sizeItems={};// keyed by baseSku+color for collapsing sizes
  itemPairs.forEach(({dataLine,descLine})=>{
    const parts=dataLine.split('\t').map(s=>s.trim());
    const qty=parseInt(parts[0])||0;
    const skuRaw=parts[1]||'';
    // Extract rate and amount: scan from the end for numbers
    let rate=0,amount=0;
    const nums=[];
    for(let k=parts.length-1;k>=2;k--){
      const v=parts[k].replace(/[$,]/g,'').trim();
      if(/^\d+\.?\d*$/.test(v))nums.unshift(parseFloat(v));
      else if(nums.length>=2)break;// stop once we have rate+amount
    }
    if(nums.length>=2){rate=nums[nums.length-2];amount=nums[nums.length-1]}
    else if(nums.length===1){amount=nums[0];rate=qty>0?rQ(nums[0]/qty):0}

    // Parse SKU — handles "JP4674 : JP4674-S" and "Screen 1"
    const skuColonParts=skuRaw.split(/\s*:\s*/);
    let baseSku=(skuColonParts[0]||skuRaw).trim();
    let fullSku=(skuColonParts[1]||baseSku).trim();

    // Fallback: if baseSku doesn't look like a product SKU, scan all parts for alphanumeric SKU (2 letters + 4 digits, e.g. EK0086)
    const ALPHA_SKU_RE=/\b([A-Za-z]{2}\d{4})\b/;
    if(baseSku&&!/^[A-Za-z]{2}\d{4}/.test(baseSku)&&!_products.some(p=>p.sku.toLowerCase()===baseSku.toLowerCase())){
      for(let pi=0;pi<parts.length;pi++){const am=parts[pi].match(ALPHA_SKU_RE);if(am){baseSku=am[1].toUpperCase();fullSku=baseSku;break}}
      // Also check description line for SKU
      if(!/^[A-Za-z]{2}\d{4}/.test(baseSku)&&descLine){const dm=descLine.match(ALPHA_SKU_RE);if(dm){baseSku=dm[1].toUpperCase();fullSku=baseSku}}
    }

    // Detect size suffix from fullSku
    const sizeMatch=fullSku.match(SZ_RE);
    let size=null;
    if(sizeMatch){
      size=sizeMatch[1].toUpperCase();
      baseSku=baseSku.replace(SZ_RE,'').replace(/-$/,'').trim();
    }
    if(!size){const bsm=baseSku.match(SZ_RE);if(bsm){size=bsm[1].toUpperCase();baseSku=baseSku.replace(SZ_RE,'').replace(/-$/,'').trim()}}

    // Parse description line for product name and color
    const description=(descLine||'').replace(/\t.*/,'').trim();
    let color='';
    // NSA descriptions use both - and – (en-dash): "Adidas Creator Tee - Black - S" or "Pant – White Pins"
    const DASH=/\s*[-–—]\s*/;
    const colorSizeMatch=description.match(/\s*[-–—]\s*([A-Za-z][A-Za-z\s,\/]+?)\s*[-–—]\s*(?:XXS|XS|YXS|YS|YM|YL|YXL|S|M|L|XL|2XL|3XL|4XL|5XL|OSFA)\s*$/i);
    if(colorSizeMatch)color=colorSizeMatch[1].trim();
    else{
      // Try: "Name – Color" or "Name – Color Variant" (no size at end)
      const colorOnly=description.match(/\s*[-–—]\s*([A-Za-z][A-Za-z\s,\/]+?)\s*$/);
      if(colorOnly&&!/(?:color|print|press|emb|screen|knicker|regular)/i.test(colorOnly[1]))color=colorOnly[1].trim();
    }
    // Clean product name (strip color/variant suffix from description)
    let productName=description;
    if(color){productName=description.replace(new RegExp('\\s*[-–—]\\s*'+color.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+'.*$','i'),'').trim()}

    // Detect shipping lines
    if(/^shipping$/i.test(baseSku)||/^shipping$/i.test(description)){
      result.shipping+=amount||rate;return;
    }

    // Detect decoration lines: "Screen 1", "Screen 2", "Emb 1", "DTF 1", etc.
    const isDecoration=/^(Screen|Emb|Embr|DTF|Heat|Vinyl|Sublim|Deco)\s*\d*$/i.test(baseSku);
    if(isDecoration){
      // Parse decoration type from description: "Screen Print 1 Color", "Embroidery up to 8000 stitches"
      let decoType='art';
      if(/screen\s*print/i.test(description))decoType='screen_print';
      else if(/embroid/i.test(description))decoType='embroidery';
      else if(/dtf|heat\s*trans/i.test(description))decoType='dtf';
      // Count colors from description: "Screen Print 2 Color" → 2
      const colorCountMatch=description.match(/(\d+)\s*colou?r/i);
      const colors=colorCountMatch?parseInt(colorCountMatch[1]):1;
      result.lineItems.push({sku:baseSku,description,quantity:qty,rate:rate||0,amount:amount||0,
        isDecoration:true,decoType,colors,sizes:{},raw:dataLine});
      return;
    }

    // Collapse sizes: same baseSku+color → one item with size breakdown
    const collapseKey=baseSku+(color?'||'+color:'');
    if(size&&baseSku){
      if(!sizeItems[collapseKey]){
        sizeItems[collapseKey]={sku:baseSku,description:productName,color,quantity:0,rate,amount:0,isDecoration:false,sizes:{},raw:dataLine};
      }
      sizeItems[collapseKey].sizes[size]=(sizeItems[collapseKey].sizes[size]||0)+qty;
      sizeItems[collapseKey].quantity+=qty;
      sizeItems[collapseKey].amount+=amount;
      if(color&&!sizeItems[collapseKey].color)sizeItems[collapseKey].color=color;
      if(productName&&!sizeItems[collapseKey].description)sizeItems[collapseKey].description=productName;
    } else {
      // No size detected — single item or embedded sizes in description
      const sizes={};
      // Check for letter sizes: "12/S, 14/M, 8/L"
      const embSizeRe=/(\d+)\s*\/\s*(XXS|XS|YXS|YS|YM|YL|YXL|S|M|L|XL|2XL|3XL|4XL|5XL)/gi;
      let embMatch;while((embMatch=embSizeRe.exec(description)))sizes[embMatch[2].toUpperCase()]=parseInt(embMatch[1]);
      // Check for numeric sizes: "1/38 – knickers 1/40 – knickers 2/42" → sizes {38:1, 40:1, 42:2}
      if(Object.keys(sizes).length===0){
        const numSizeRe=/(\d+)\s*\/\s*(\d{2,3})/g;
        let nm;while((nm=numSizeRe.exec(description)))sizes[nm[2]]=(sizes[nm[2]]||0)+parseInt(nm[1]);
      }
      if(Object.keys(sizes).length===0)sizes['OSFA']=qty;
      result.lineItems.push({sku:baseSku||'MISC',description:productName||description,color,quantity:qty,rate,amount,isDecoration:false,sizes,raw:dataLine});
    }
  });

  // Add collapsed size items to lineItems
  Object.values(sizeItems).forEach(it=>{
    if(it.quantity>0&&it.rate===0&&it.amount>0)it.rate=rQ(it.amount/it.quantity);
    result.lineItems.push(it);
  });

  // ── Confidence scoring ──
  if(result.docNumber&&result.customerName&&result.lineItems.length>0)result.confidence='high';
  else if((result.docNumber||result.customerName)&&result.lineItems.length>0)result.confidence='medium';
  else{
    result.confidence='low';
    if(result.lineItems.length===0)result.warnings.push('No line items detected. The PDF format may not be recognized — try the paste option instead.');
    else result.warnings.push('Missing document number or customer. Please verify the extracted data.');
  }
  return result;
};
// Split multi-invoice PDF into separate documents by document number
const parseNetSuitePdfMulti=(pages,docType,products)=>{
  const DOC_RE=/(?:Estimate|EST)[#\s:]*#?(EST-?\d+)|(?:Sales Order|SO)[#\s:]*#?(SO-?\d+)|(?:Purchase Order|PO)[#\s:]*#?(PO-?\d+)|(?:Invoice|INV)[#\s:]*#?(INV-?\d+)|#(EST\d+)|#(SO-?\d+)|#(PO-?\d+)|#(INV-?\d+)|(?:Estimate|Sales Order|Invoice|Purchase Order)\s*#?\s*(\d{3,})/i;
  // Detect document number on each page
  const pageDocNums=pages.map(pt=>{const m=pt.match(DOC_RE);return m?(m.find((v,i)=>i>0&&v)||''):''});
  // Group pages by document number; pages without a doc number attach to the previous page's doc
  const groups={};const order=[];
  let currentDoc='__unknown__';
  pageDocNums.forEach((dn,i)=>{
    if(dn)currentDoc=dn;
    if(!groups[currentDoc]){groups[currentDoc]=[];order.push(currentDoc)}
    groups[currentDoc].push(pages[i]);
  });
  // If only one group, just parse normally (single document)
  if(order.length<=1){
    const allText=pages.join('\n');
    return[parseNetSuitePdf(allText,docType,products)];
  }
  // Parse each group as a separate document
  return order.map(docNum=>{
    const text=groups[docNum].join('\n');
    return parseNetSuitePdf(text,docType,products);
  });
};
